class Playground {
  async run(inputs) {
    const rows = inputs[0].split(';').map(r => r.trim().split(',').map(v => parseInt(v.trim())));
    const numRows = rows.length;
    const numCols = rows[0].length;

    this.grid.init(rows);
    this.ptr.set('islands', 0);
    this.log(`Grid: ${numRows}x${numCols}`);
    await this.await();

    const visitedData = Array.from({length: numRows}, () => Array(numCols).fill(false));
    this.visited.init(visitedData);
    this.log('Initialized visited matrix (all false)');
    await this.await();

    let islands = 0;
    const dirs = [[-1,0],[1,0],[0,-1],[0,1]];

    for (let r = 0; r < numRows; r++) {
      for (let c = 0; c < numCols; c++) {
        this.grid.highlight(r, c, '#3b82f6');
        this.log(`Checking cell (${r},${c}) = ${rows[r][c]}`);
        await this.await();

        if (rows[r][c] === 1 && !visitedData[r][c]) {
          islands++;
          this.ptr.set('islands', islands);
          this.log(`Found island #${islands} -- Starting BFS from (${r},${c})`);
          await this.await();

          visitedData[r][c] = true;
          this.visited.setCell(r, c, true);
          this.queue.enqueue(`(${r},${c})`);
          this.log(`Enqueue (${r},${c})`);
          await this.await();

          while (!this.queue.isEmpty()) {
            const front = this.queue.dequeue();
            const coords = front.slice(1,-1).split(',');
            const cr = parseInt(coords[0]);
            const cc = parseInt(coords[1]);

            this.grid.highlight(cr, cc, '#ec4899');
            this.log(`Dequeue ${front} -- processing`);
            await this.await();

            for (const [dr, dc] of dirs) {
              const nr = cr + dr;
              const nc = cc + dc;
              if (nr >= 0 && nr < numRows && nc >= 0 && nc < numCols
                  && rows[nr][nc] === 1 && !visitedData[nr][nc]) {

                this.grid.highlight(nr, nc, '#f59e0b');
                visitedData[nr][nc] = true;
                this.visited.setCell(nr, nc, true);
                this.queue.enqueue(`(${nr},${nc})`);
                this.log(`Found land neighbor (${nr},${nc}) -- enqueued`);
                await this.await();
              }
            }

            this.grid.highlight(cr, cc, '#10b981');
          }
        } else {
          this.grid.clearHighlights();
        }
      }
    }

    this.grid.clearHighlights();
    this.log(`Total islands found: ${islands}`);
    return islands;
  }
}
